#include "kernel_operator.h"
#include "ca6k03129_custom_tiling.h"

constexpr int32_t BUFFER_NUM = 2;

class KernelStdMean {
public:
    __aicore__ inline KernelStdMean() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR stds, GM_ADDR means,
                                uint32_t batchSize, uint32_t channel,
                                uint32_t height, uint32_t width,
                                uint32_t tileHeight, uint32_t tileWidth)
    {
        totalB_ = batchSize;
        totalC_ = channel;
        totalH_ = height;
        totalW_ = width;
        tileH_ = tileHeight;
        tileW_ = tileWidth;
        xGm_.SetGlobalBuffer((__gm__ float*)x, batchSize * channel * height * width);
        stdsGm_.SetGlobalBuffer((__gm__ float*)stds, channel);
        meansGm_.SetGlobalBuffer((__gm__ float*)means, channel);

        pipe_.InitBuffer(inQueue_, BUFFER_NUM, tileH_ * tileW_ * sizeof(float));
        pipe_.InitBuffer(varBuf_, 1, sizeof(float));
    }

    __aicore__ inline void Process()
    {
        uint32_t blockIdx = AscendC::GetBlockIdx();
        if (blockIdx >= totalC_) return;

        float sum = 0.0f;
        float sumSq = 0.0f;
        uint32_t count = 0;

        for (uint32_t b = 0; b < totalB_; ++b) {
            for (uint32_t h = 0; h < totalH_; h += tileH_) {
                uint32_t curTileH = tileH_;
                if (h + curTileH > totalH_) curTileH = totalH_ - h;

                uint32_t offset = (b * totalC_ + blockIdx) * totalH_ * totalW_
                                + h * totalW_;
                uint32_t tileSize = curTileH * totalW_;

                AscendC::LocalTensor<float> tile = inQueue_.AllocTensor<float>();
                AscendC::DataCopy(tile, xGm_[offset], tileSize);
                inQueue_.EnQue(tile);

                AscendC::LocalTensor<float> tileDeq = inQueue_.DeQue<float>();
                for (uint32_t i = 0; i < tileSize; ++i) {
                    float val = tileDeq(i);
                    sum += val;
                    sumSq += val * val;
                }
                count += tileSize;
                inQueue_.FreeTensor(tileDeq);
            }
        }

        float mean = sum / static_cast<float>(count);
        float var = (sumSq - sum * mean) / static_cast<float>(count - 1);

        // compute std using AscendC Sqrt on a one-element local tensor
        AscendC::LocalTensor<float> varTensor = varBuf_.AllocTensor<float>();
        varTensor(0) = var;
        AscendC::Sqrt(varTensor, varTensor, 1);
        float std = varTensor(0);
        varBuf_.FreeTensor(varTensor);

        meansGm_.SetValue(blockIdx, mean);
        stdsGm_.SetValue(blockIdx, std);
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueue_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> varBuf_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> stdsGm_;
    AscendC::GlobalTensor<float> meansGm_;

    uint32_t totalB_ {0};
    uint32_t totalC_ {0};
    uint32_t totalH_ {0};
    uint32_t totalW_ {0};
    uint32_t tileH_ {64};
    uint32_t tileW_ {512};
};

extern "C" __global__ __aicore__ void ca6k_03129_custom(GM_ADDR x, GM_ADDR stds, GM_ADDR means,
                                                        GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelStdMean op;
    op.Init(x, stds, means,
            tiling_data.batchSize, tiling_data.channel,
            tiling_data.height, tiling_data.width,
            tiling_data.tileHeight, tiling_data.tileWidth);
    op.Process();
}
